// Build an outbound Tai API request from a tai-out Kafka message.
// Message envelope:
//   {
//     operation:      'confirm_bill_sync' | 'confirm_invoice_sync' |
//                     'post_invoice_payment' | 'post_bill_payment',
//     payload:        { billId|invoiceId, status, transactionId, ... },
//     correlation_id: '...',
//     _retry_count:   0
//   }
//
// Auth: Tai uses the API key in the Authorization header as 'ApiKey <key>'.
// Verify the exact header name against /PublicApi/swagger on your TMS instance
// if calls return 401.
const kafkaMessage = $input.item.json;
const msg = typeof kafkaMessage.value === 'string' ? JSON.parse(kafkaMessage.value) : kafkaMessage.value;
if (!msg || !msg.operation) throw new Error('invalid tai-out message: missing operation');

const baseUrl = $env.TAI_API_URL;
const apiKey  = $env.TAI_API_KEY;
if (!baseUrl || baseUrl === 'CHANGE_ME') throw new Error('TAI_API_URL not configured');
if (!apiKey  || apiKey  === 'CHANGE_ME') throw new Error('TAI_API_KEY not configured');

const OPS = {
  confirm_bill_sync:     { method: 'PUT',  path: '/Accounting/v2/Bills/Sync' },
  confirm_invoice_sync:  { method: 'PUT',  path: '/Accounting/v2/Invoices/Sync' },
  // Payment posting paths — verify exact paths against Tai Swagger before use
  post_invoice_payment:  { method: 'POST', path: '/Accounting/v2/InvoicePayments' },
  post_bill_payment:     { method: 'POST', path: '/Accounting/v2/BillPayments' },
};
const op = OPS[msg.operation];
if (!op) throw new Error(`unsupported Tai operation: ${msg.operation}`);

return {
  json: {
    url:            `${baseUrl}${op.path}`,
    method:         op.method,
    body:           msg.payload || {},
    correlation_id: msg.correlation_id || $execution.id,
    retry_count:    msg._retry_count || 0,
    max_retries:    5,
    operation:      msg.operation,
    original:       msg,
    _apiKey:        apiKey
  }
};

const resp = $input.item.json;
const ctx  = $('Validate + Resolve').item.json;
return [{ json: {
  success: true,
  workflow: 'tai-outbound',
  operation: ctx.operation,
  correlation_id: ctx.correlation_id,
  response: resp,
  timestamp: new Date().toISOString()
}}];

const error = $input.item.json;
const ctx = ($('Validate + Resolve').item || {}).json || {};
const retryCount = ctx.retry_count || 0;
const maxRetries = ctx.max_retries || 5;
const status = error.status || error.statusCode || (error.response && error.response.status) || 0;
const isTransient = status === 429 || (status >= 500 && status < 600);
const shouldRetry = isTransient && retryCount < maxRetries;
return [{ json: {
  workflow: 'tai-outbound',
  operation: ctx.operation,
  correlation_id: ctx.correlation_id,
  error_message: error.message || 'unknown error',
  status,
  retry_count: retryCount,
  max_retries: maxRetries,
  should_retry: shouldRetry,
  retry_delay_ms: Math.min(60000, 1000 * Math.pow(2, retryCount)) + Math.floor(Math.random() * 500),
  requeue_payload: { ...(ctx.original || {}), _retry_count: retryCount + 1 },
  timestamp: new Date().toISOString()
}}];
